"""Тесты HashSidecarService: создание/обновление sidecar .md5, заполнение doc.hash."""from __future__ import annotationsimport threadingimport timefrom pathlib import Pathimport pytestfrom src.modules.file_discovery import (    DiscoveryConfig,    DiscoveryService,    HashSidecarService,)def test_ensure_hashes_fills_hash_and_creates_sidecar(tmp_path: Path) -> None:    (tmp_path / "f.txt").write_text("hello")    discovery = DiscoveryService()    hash_svc = HashSidecarService()    config = DiscoveryConfig(path=str(tmp_path), extensions={"*"})    docs = discovery.discover_files(config)    assert len(docs) == 1    assert docs[0].hash is None    hash_svc.ensure_hashes(docs)    assert docs[0].hash is not None    assert len(docs[0].hash) == 32    sidecar = tmp_path / "f.txt.md5"    assert sidecar.exists()    assert sidecar.read_text().strip() == docs[0].hashdef test_md5_stale_sidecar_recreated(tmp_path: Path) -> None:    f = tmp_path / "f.txt"    f.write_text("v1")    discovery = DiscoveryService()    hash_svc = HashSidecarService()    config = DiscoveryConfig(path=str(tmp_path), extensions={"*"})    docs = discovery.discover_files(config)    hash_svc.ensure_hashes(docs)    hash1 = docs[0].hash    time.sleep(0.02)    f.write_text("v2")    docs2 = discovery.discover_files(config)    hash_svc.ensure_hashes(docs2)    hash2 = docs2[0].hash    assert hash1 != hash2    assert (tmp_path / "f.txt.md5").read_text().strip() == hash2def test_md5_fresh_sidecar_not_recomputed(tmp_path: Path) -> None:    f = tmp_path / "f.txt"    f.write_text("same")    discovery = DiscoveryService()    hash_svc = HashSidecarService()    config = DiscoveryConfig(path=str(tmp_path), extensions={"*"})    docs = discovery.discover_files(config)    hash_svc.ensure_hashes(docs)    sidecar = tmp_path / "f.txt.md5"    mtime_before = sidecar.stat().st_mtime    docs2 = discovery.discover_files(config)    hash_svc.ensure_hashes(docs2)    mtime_after = sidecar.stat().st_mtime    assert mtime_after == mtime_beforedef test_ensure_hashes_respects_cancel_event(tmp_path: Path) -> None:    for i in range(30):        (tmp_path / f"f{i}.txt").write_text("x")    discovery = DiscoveryService()    hash_svc = HashSidecarService()    config = DiscoveryConfig(path=str(tmp_path), extensions={"*"})    docs = discovery.discover_files(config)    cancel = threading.Event()    cancel.set()    hash_svc.ensure_hashes(docs, cancel_event=cancel)    filled = sum(1 for d in docs if d.hash is not None)    assert filled == 0